const text = $json.message_text || '';
const lower = text.toLowerCase();
const handoffTerms = ['diagnose', 'procedure should i get', 'urgent', 'emergency', 'pay now', 'which clinic'];
const handoffRequired = handoffTerms.some((term) => lower.includes(term));
return [{
  json: {
    ...$json,
    llm_classification_raw: JSON.stringify({
      handoff_required: handoffRequired,
      intent: 'kbeauty_trip_intake',
      risk_level: handoffRequired ? 'needs_human_review' : 'low',
      known_fields: {},
      missing_fields: ['travel_dates', 'preferred_language', 'budget_range'],
      safety_notes: ['No medical advice, diagnosis, procedure recommendation, clinic choice, or payment handling.']
    })
  }
}];

const fallback = {
  handoff_required: true,
  intent: 'parse_error',
  risk_level: 'needs_human_review',
  known_fields: {},
  missing_fields: [],
  safety_notes: ['Classification JSON failed validation; route to human review.']
};
let parsed;
try {
  parsed = JSON.parse($json.llm_classification_raw || '{}');
} catch (error) {
  parsed = fallback;
}
const valid = typeof parsed.handoff_required === 'boolean' && typeof parsed.intent === 'string';
const classification = valid ? parsed : fallback;
return [{ json: { ...$json, classification } }];
